{"file_text": "using RecipeCommunity.Models;

namespace RecipeCommunity.Services;

public class RecipeService
{
    private readonly List<Recipe> _recipes = new()
    {
        new Recipe { Id = 1, Title = "Classic Margherita Pizza", Category = "Italian", Ingredients = "Pizza dough\nSan Marzano tomatoes\nFresh mozzarella\nFresh basil\nOlive oil\nSalt", Steps = "1. Preheat oven to 475°F (245°C).\n2. Roll out dough on a floured surface.\n3. Spread crushed tomatoes evenly.\n4. Tear mozzarella and distribute over sauce.\n5. Bake for 10-12 minutes until crust is golden.\n6. Top with fresh basil and a drizzle of olive oil.", AverageRating = 4.5, RatingCount = 12 },
        new Recipe { Id = 2, Title = "Chicken Tikka Masala", Category = "Indian", Ingredients = "Chicken breast\nYogurt\nGaram masala\nTurmeric\nCumin\nTomato sauce\nHeavy cream\nGarlic\nGinger\nOnion", Steps = "1. Marinate chicken in yogurt and spices for 2 hours.\n2. Grill or pan-fry chicken until charred.\n3. Sauté onion, garlic, and ginger.\n4. Add tomato sauce and spices, simmer 15 min.\n5. Stir in cream, add chicken pieces.\n6. Simmer 10 more minutes. Serve with rice.", AverageRating = 4.8, RatingCount = 24 },
        new Recipe { Id = 3, Title = "Beef Tacos", Category = "Mexican", Ingredients = "Ground beef\nTaco seasoning\nCorn tortillas\nLettuce\nTomato\nCheddar cheese\nSour cream\nSalsa", Steps = "1. Brown ground beef in a skillet.\n2. Add taco seasoning and water, simmer 5 min.\n3. Warm tortillas in a dry pan.\n4. Assemble tacos with beef and toppings.\n5. Serve with salsa and sour cream.", AverageRating = 4.2, RatingCount = 8 },
        new Recipe { Id = 4, Title = "Pad Thai", Category = "Thai", Ingredients = "Rice noodles\nShrimp or tofu\nEgg\nBean sprouts\nGreen onions\nPeanuts\nLime\nFish sauce\nTamarind paste\nSugar", Steps = "1. Soak rice noodles in warm water 30 min.\n2. Make sauce: mix tamarind, fish sauce, and sugar.\n3. Stir-fry shrimp/tofu, push aside, scramble egg.\n4. Add drained noodles and sauce, toss.\n5. Add bean sprouts and green onions.\n6. Serve with crushed peanuts and lime wedge.", AverageRating = 4.6, RatingCount = 15 },
        new Recipe { Id = 5, Title = "Chocolate Lava Cake", Category = "Desserts", Ingredients = "Dark chocolate\nButter\nEggs\nSugar\nFlour\nVanilla extract", Steps = "1. Preheat oven to 425°F (220°C).\n2. Melt chocolate and butter together.\n3. Whisk eggs, sugar, and vanilla until thick.\n4. Fold in chocolate mixture and flour.\n5. Pour into greased ramekins.\n6. Bake 12-14 minutes (center should be soft).\n7. Invert onto plate and serve immediately.", AverageRating = 4.9, RatingCount = 30 },
        new Recipe { Id = 6, Title = "Caesar Salad", Category = "Salads", Ingredients = "Romaine lettuce\nParmesan cheese\nCroutons\nCaesar dressing\nLemon juice\nGarlic\nAnchovy paste", Steps = "1. Wash and chop romaine lettuce.\n2. Make dressing: whisk garlic, anchovy paste, lemon juice, and olive oil.\n3. Toss lettuce with dressing.\n4. Top with shaved Parmesan and croutons.\n5. Serve immediately.", AverageRating = 3.9, RatingCount = 6 },
        new Recipe { Id = 7, Title = "Spaghetti Carbonara", Category = "Italian", Ingredients = "Spaghetti\nGuanciale or pancetta\nEggs\nPecorino Romano\nBlack pepper", Steps = "1. Cook spaghetti in salted water until al dente.\n2. Crisp guanciale in a pan.\n3. Whisk eggs with grated pecorino and pepper.\n4. Toss hot pasta with guanciale (off heat).\n5. Quickly stir in egg mixture to create creamy sauce.\n6. Serve with extra pecorino and pepper.", AverageRating = 4.7, RatingCount = 19 },
        new Recipe { Id = 8, Title = "Mango Sticky Rice", Category = "Thai", Ingredients = "Glutinous rice\nCoconut milk\nSugar\nSalt\nRipe mango", Steps = "1. Soak sticky rice for 4+ hours.\n2. Steam rice for 20-25 minutes.\n3. Heat coconut milk with sugar and salt.\n4. Mix half the coconut sauce into cooked rice.\n5. Let rice absorb sauce for 30 min.\n6. Serve with sliced mango and remaining sauce drizzled on top.", AverageRating = 4.4, RatingCount = 11 },
    };

    private int _nextId = 9;

    public IReadOnlyList<string> GetCategories()
    {
        return _recipes.Select(r => r.Category).Distinct().OrderBy(c => c).ToList();
    }

    public IReadOnlyList<Recipe> GetRecipesByCategory(string category)
    {
        return _recipes.Where(r => r.Category.Equals(category, StringComparison.OrdinalIgnoreCase)).ToList();
    }

    public Recipe? GetRecipeById(int id)
    {
        return _recipes.FirstOrDefault(r => r.Id == id);
    }

    public IReadOnlyList<Recipe> GetAllRecipes()
    {
        return _recipes.AsReadOnly();
    }

    public void AddRating(int recipeId, int stars)
    {
        var recipe = _recipes.FirstOrDefault(r => r.Id == recipeId);
        if (recipe is null || stars < 1 || stars > 5) return;

        var totalStars = recipe.AverageRating * recipe.RatingCount;
        recipe.RatingCount++;
        recipe.AverageRating = Math.Round((totalStars + stars) / recipe.RatingCount, 1);
    }

    public void SubmitRecipe(RecipeSubmission submission)
    {
        _recipes.Add(new Recipe
        {
            Id = _nextId++,
            Title = submission.Title,
            Category = submission.Category,
            Ingredients = submission.Ingredients,
            Steps = submission.Steps,
            AverageRating = 0,
            RatingCount = 0
        });
    }
}
