arguments.new_str:
@page "/"
@using RecipeCommunity.Services
@inject RecipeService RecipeService

<PageTitle>Recipe Community - Home</PageTitle>

<div class="container">
    <div class="text-center my-4">
        <h1>🍳 Recipe Community</h1>
        <p class="lead">Discover, share, and rate delicious recipes from around the world.</p>
    </div>

    <h2 class="mb-3">Browse by Category</h2>
    <div class="row">
        @foreach (var category in RecipeService.GetCategories())
        {
            <div class="col-md-4 mb-3">
                <div class="card h-100">
                    <div class="card-body text-center">
                        <h5 class="card-title">@GetCategoryEmoji(category) @category</h5>
                        <p class="card-text text-muted">
                            @RecipeService.GetRecipesByCategory(category).Count recipe(s)
                        </p>
                        <a href="recipes/@category" class="btn btn-outline-primary">View Recipes</a>
                    </div>
                </div>
            </div>
        }
    </div>
</div>

@code {
    private static string GetCategoryEmoji(string category) => category switch
    {
        "Italian" => "🇮🇹",
        "Indian" => "🇮🇳",
        "Mexican" => "🇲🇽",
        "Thai" => "🇹🇭",
        "Desserts" => "🍰",
        "Salads" => "🥗",
        _ => "🍽️"
    };
}

