                <div class="form-text">Enter one ingredient per line.</div>
            </div>

            <div class="mb-3">
                <label for="steps" class="form-label">Steps</label>
                <InputTextArea id="steps" class="form-control" rows="6" @bind-Value="Submission.Steps" placeholder="1. First step&#10;2. Second step&#10;3. Third step" />
                <div class="form-text">Number your steps for clarity.</div>
            </div>

            <button type="submit" class="btn btn-success"
