@page "/recipes"
@page "/recipes/{Category}"
@using RecipeCommunity.Services
@inject RecipeService RecipeService

<PageTitle>Recipes - @(Category ?? "All")</PageTitle>

<div class="container">
    <h1 class="mb-3">@(Category is not null ? $"📖 {Category} Recipes" : "📖 All Recipes")</h1>

    @if (Category is null)
    {
        <p>Select a category to browse recipes, or view all recipes below.</p>
        <div class="mb-3">
            @foreach (var cat in RecipeService.GetCategories())
            {
                <a href="recipes/@cat" class="btn btn-sm btn-outline-secondary me-2 mb-2">@cat</a>
            }
        </div>
    }

    <div class="row">
        @foreach (var recipe in Recipes)
        {
            <div class="col-md-6 mb-3">
                <div class="card">
                    <div class="card-body">
                        <h5 class="card-title">@recipe.Title</h5>
                        <span class="badge bg-secondary">@recipe.Category</span>
                        <p class="mt-2 mb-1">
                            <span class="text-warning">@(new string('★', (int)Math.Round(recipe.AverageRating)))@(new string('☆', 5 - (int)Math.Round(recipe.AverageRating)))</span>
                            <small class="text-muted">(@recipe.AverageRating / 5, @recipe.RatingCount ratings)</small>
                        </p>
                        <a href="recipe/@recipe.Id" class="btn btn-primary btn-sm mt-2">View Recipe</a>
                    </div>
                </div>
            </div>
        }
    </div>

    @if (!Recipes.Any())
    {
        <div class="alert alert-info">No recipes found in this category.</div>
    }
</div>

@code {
    [Parameter]
    public string? Category { get; set; }

    private IReadOnlyList<RecipeCommunity.Models.Recipe> Recipes { get; set; } = [];

    protected override void OnParametersSet()
    {
        Recipes = Category is not null
            ? RecipeService.GetRecipesByCategory(Category)
            : RecipeService.GetAllRecipes();
    }
}

